    assert_eq!(verification["executor_backend"], "opencode_cli");

    let review_ensemble = summarize_agent_route_from_snapshot(
        &serde_json::Value::Null,
        agent_system,
        "review_ensemble",
    );
    let review_ensemble_fanout = review_ensemble["fanout_executor_backends"]
        .as_array()
