    assert!(review_ensemble_fanout
        .iter()
        .any(|value| value == "qwen_cli"));
    assert!(review_ensemble_fanout
        .iter()
        .any(|value| value == "hermes_cli"));
    assert!(review_ensemble_fanout
        .iter()
        .any(|value| value == "opencode_cli"));
}

